import{_ as o,c as l,o as a,a1 as t}from"./chunks/framework.AlEHVjdq.js";const m=JSON.parse('{"title":"2025 AI Review","description":"","frontmatter":{"title":"2025 AI Review","customTag":"blog>AIGC","date":"2025-04-19T00:00:00.000Z","editLink":true},"headers":[],"relativePath":"blog/2025-AI-review.md","filePath":"blog/2025-AI-review.md","lastUpdated":1768044054000}'),g={name:"blog/2025-AI-review.md"};function s(n,p,i,e,r,u){return a(),l("div",null,[...p[0]||(p[0]=[t('<h1 id="_2025-ai-review" tabindex="-1">2025 AI review <a class="header-anchor" href="#_2025-ai-review" aria-label="Permalink to &quot;2025 AI review&quot;">​</a></h1><p>2022 年 ChatGPT 发布至今，</p><p>已经有三年的时间，</p><p>从客观的角度来讲，</p><p>这三年中，</p><p>宏观和微观层面，</p><p>也许都有挺大的变化。</p><p>而从个人的体感来讲，</p><p>今年的变化应该是最大的。</p><p>具体体现在</p><ol><li>AI 似乎成为了主流词汇</li><li><strong>个人日常使用不愿离开 AI</strong></li><li><strong>工作中也有些 AI 工程层相关</strong></li><li><strong>大多行业及其应用都在集成 AI</strong></li></ol><p>也许你会和我有同样的感受，</p><p>所以，我希望在今年也记录下关于 AI 的内容。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766216835068-image.png" alt=""></p><p>本文会从偏客观和偏主观的两个方面细化。</p><ul><li><strong>偏客观：<strong>从</strong>2025 年的 AI 相关发布情况，从而去尝试总结今年发展。</strong></li><li><strong>偏主观</strong>：从<strong>日常使用 AI、AI 对我的影响、重新看待 AI</strong>这三个方面梳理并结合具体的例子，来发表我个人的想法（不一定对）。</li></ul><p>实际上，</p><p>写这篇文章对我来说有点挑战。</p><p>我不确定分主/客观的逻辑是否能讲清楚，</p><p>我不确定文笔是否能让不同的人好理解，</p><p>我不确定这些内容信息量如何，不确定长文/短文。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766216757599-image.png" alt=""></p><p>但我还是希望先记录下来，</p><p>希望其中有些内容能引起你的共鸣，</p><p><strong>也许，这也算传递些增量的信息。</strong></p><h2 id="一、我眼中的-2025-ai" tabindex="-1">一、我眼中的 2025 AI <a class="header-anchor" href="#一、我眼中的-2025-ai" aria-label="Permalink to &quot;一、我眼中的 2025 AI&quot;">​</a></h2><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766219167611-generated-1766219167611-48agxpyvk7e.png" alt="图片-1"></p><p>如果让我总结我眼中 2025 AI 的发展，</p><p>大概会有几个关键点吧。</p><ul><li><strong>推理模型兴起</strong></li><li><strong>标准协议制定</strong></li><li><strong>工程基建补齐</strong></li><li><strong>应用形态创新</strong></li></ul><p>下方我们具体来看看吧</p><p>**模型层：**推理型模型成为主流能力范式</p><ul><li><strong>2024 状态</strong>：生成式模型主导市场，依赖预训练规模扩展提升能力，但 Scaling Law 收益递减，模型缺乏深度推理能力、OpenAI O1 推理模型发布</li><li><strong>2025 突破</strong>：推理时计算成为新范式，模型具备 System 2 深度思考能力，从&quot;快速生成&quot;转向&quot;深度推理&quot;，在复杂任务上质变式提升。</li><li><strong>标志事件</strong>：OpenAI o1/o3 系列率先验证推理模型路径；DeepSeek R1 以开源方式证明推理能力可平民化，行业形成共识，其余厂家也采用推理模型路径；</li></ul><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766821582861-generated-1766821582861-3eocyd71vzb.png" alt="图片-1"></p><p>**协议层：**Agent / Tool 等关键协议逐步标准化</p><ul><li><strong>2024 状态</strong>：各家 AI 厂商各自为战，工具调用、Agent 通信、UI 交互均采用私有协议，生态碎片化严重，开发者需要为不同平台重复开发适配层。MCP 协议刚推出，但还没有成主流规范。</li><li><strong>2025 突破</strong>：今年协议逐步趋向行业统一，覆盖工具集成（MCP）、Agent 协作（A2A）、能力封装（Skills）等协议，AI 生态从封闭走向互操作，开发者可以&quot;一次编写，到处运行&quot;。</li><li><strong>标志事件</strong>：MCP (Model Context Protocol)协议发布及厂商跟进支持；Google 推动 A2A(Agent-to-Agent)；Skills 能力推出，后续演变成通用标准。</li></ul><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766821135293-generated-1766821135293-99eqzfotjkc.png" alt="图片-1"></p><p>**工程层：**AI 应用工程化基础设施补齐</p><ul><li><strong>2024 状态</strong>：AI 应用开发处于&quot;手工作坊&quot;阶段，框架零散且功能单一，缺乏成熟的编排引擎、调试工具、可观测性方案，开发者需要自行拼接 Prompt 管理、工具调用、状态管理等基础能力。</li><li><strong>2025 突破</strong>：工程范式演进（从 Prompt Engineering 演变 Context Engineering）;<strong>基础设施</strong>补齐（可观测性、成本监控、部署平台成熟）;<strong>框架生态</strong>完善（通用 Agent SDK、编排引擎、记忆管理、工具调用），开发者可以像构建传统应用一样构建 AI 应用，具备完整的开发、调试、监控、部署能力。</li><li><strong>标志事件</strong>：Context Engineering 提出、Multi-Agent 编排模式标准化、Human-in-the-Loop (HITL) 模式出现；Anthropic Claude Agent SDK 发布、LangGraph 1.0 发布、MCP Servers 生态丰富**。**</li></ul><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766821362807-generated-1766821362807-jndvbj04ql9.png" alt="图片-1"></p><p>**应用层：**Agent 应用新形态的出现</p><ul><li><strong>2024 状态</strong>：AI 应用以 Copilot 辅助模式为主（代码补全、文本续写），交互形态单一（纯文本对话框），能力边界清晰但狭窄（单轮问答、被动响应），缺乏主动性与持续性，无法完成复杂多步骤任务，更像&quot;智能工具&quot;而非&quot;智能助手&quot;。</li><li><strong>2025 突破</strong>：从 Copilot（辅助）演进到 Agent（自主），从通用对话扩展到垂直场景深度渗透，从单一文本交互拓展到多模态人机协作，Coding Agent 应用验证 Agent 商业价值，Agent 开始具备任务规划、工具调用、持续执行、主动反馈等自主能力。</li><li><strong>标志事件</strong>：Manus 发布，全球首款通用型 Agent；Claude Code, Cursor 等 AI 编程工具发布；客服、销售、数据分析、设计等领域专用 Agent，如 Lovart Agent。</li></ul><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766821400957-generated-1766821400957-ybp5gemtns.png" alt="图片-2"></p><p>是吧，短短一年之中，</p><p>AI 在模型层、协议层、工程层、应用层都有所进展，</p><p>而 AI Agent 应用也开始了从“可提问”逐渐进入“可执行”。</p><p>讲完了 2025 偏宏观层面 AI 的发展，</p><p>那么聚焦到我个人，</p><p>我希望与你分享我日常如何使用 AI。</p><h2 id="二、我如何使用-ai" tabindex="-1">二、我如何使用 AI <a class="header-anchor" href="#二、我如何使用-ai" aria-label="Permalink to &quot;二、我如何使用 AI&quot;">​</a></h2><p>目前可以说日常已经离不开 AI，</p><p>或者说没有 AI 的话，</p><p>我的效率会有所降低。</p><p>而自己主要是用在下方几个方面。</p><h3 id="_2-1-信息处理" tabindex="-1">2.1 信息处理 <a class="header-anchor" href="#_2-1-信息处理" aria-label="Permalink to &quot;2.1 信息处理&quot;">​</a></h3><p>信息处理是一个比较抽象的词，</p><p>我们在这里，将其简化为</p><p><strong>“输入 → 提炼 → 关联 → 梳理 → 输出”</strong></p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766538853665-image.png" alt=""></p><p>实际上，你会发现每个环节都可以有 AI 的参与。</p><p><strong>输入</strong></p><p>AI 能够根据你的语意要求，</p><p>从而去检索对应的资料信息。</p><p>如果你用过 DeepResearch，</p><p>大概能理解我想表达的意思。</p><p>虽然他无法保证帮你找到所有的信息，</p><p>但至少公域内的高质量信息还是能找到的。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766539222592-image.png" alt=""></p><p><strong>提炼</strong></p><p>作为一名信息爱好者，</p><p>面对日益增长的信息源，</p><p>一直在想如何提高阅读效率。</p><p>而 AI 确实能够与阅读相结合,</p><p>提供全文总结，思维导图，问答等能力，</p><p>从而辅助我们进行阅读。</p><p>如阅读 Andrej Karpathy 的 2025 年总结</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766539773478-image.png" alt=""></p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766539765826-image.png" alt=""></p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766539873950-image.png" alt=""></p><p>也许这样能够更好地理解信息吧。</p><p><strong>关联</strong></p><p>“链接”是个很神奇的动词，</p><p>有的时候能够起 1 + 1 &gt; 2 的效果，</p><p>或者我更喜欢称为**“连点成线”**。</p><p>而 AI 也能把你做找关联，以及链接的能力。</p><ul><li><p><strong>找关联</strong>：能够根据相近的意思找对应关联的信息。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766540532711-image.png" alt=""></p></li><li><p><strong>组织节点</strong>：你能把对应的信息节点进行组织。</p><p>![](<a href="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766711568495-Eido" target="_blank" rel="noreferrer">https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766711568495-Eido</a> Mind Â· 9.12am Â· 12-26.jpeg)</p></li><li><p>**链接节点：**能够把相似的内容链接在一起。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766540653140-image.png" alt=""></p></li></ul><p>而当你的节点足够多了之后，</p><p>也许你能得到一张丰富的网络。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766540779998-image.png" alt=""></p><p><strong>输出</strong></p><p>而在当我做具体写作的时候，</p><p>AI 可以给我一些建议输入，资料查询。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766541503579-image.png" alt=""></p><p>同时呢，他也可以将这些散落的点关联起来。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766541612561-image.png" alt=""></p><h3 id="_2-2-知识学习" tabindex="-1">2.2 知识学习 <a class="header-anchor" href="#_2-2-知识学习" aria-label="Permalink to &quot;2.2 知识学习&quot;">​</a></h3><p>近几年接触下来，</p><p>我感觉 AI 在知识学习方面，</p><p>能够有不错的帮助。</p><p>因为我觉得 AI 是一种新的媒介。</p><p>他能够根据场景<strong>适配内容、展示形态、提供反馈</strong>。</p><p>也就是说，<strong>“信息也许变成液态的，可交互，双向反馈的”</strong></p><p>如理解一个新的概念。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766543080190-image.png" alt=""></p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766543105767-image.png" alt=""></p><p>理解一个书籍内容</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766543812159-image.png" alt=""></p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766543871243-image.png" alt=""></p><h3 id="_2-3-日常审视" tabindex="-1">2.3 日常审视 <a class="header-anchor" href="#_2-3-日常审视" aria-label="Permalink to &quot;2.3 日常审视&quot;">​</a></h3><p>作为一名日常喜欢记录的人，</p><p>我一直想着说，</p><p>能否有个外部视角，</p><p>能够通过我记录的行为，</p><p>从而来看待我这个人。</p><p>但在前几年，</p><p>貌似并不好做这个事。</p><p>而今年貌似可以做了。</p><p>如用 notion 总结了自己写了三年的 Blog</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766551818341-img_v3_02t9_ce29dbb5-8e46-4d3c-a377-87d6dfced3eg.png" alt=""></p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766551825909-img_v3_02t9_dfc9a0fe-0a4e-4e5e-ae46-8c542fa217bg.png" alt=""></p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766551833008-img_v3_02t9_27812f7f-cc87-4f88-ace2-6d1b9a1ca85g.png" alt=""></p><p>如自己写日记，并让 AI 进行总结。</p><p>你能够看到你一段时间内的痕迹。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766626391647-image.png" alt=""></p><p>同时，你还可以看到，你没有留意到的东西。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766626445523-image1.png" alt=""></p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766626458906-image3.png" alt=""></p><p>虽然他给的回复不一定客观，</p><p>甚至可能还有些拍马屁的行为。</p><p>但也许有些外界的反馈输入，</p><p>并且自己做好判断，</p><p>也许是一个不错的输入视角。</p><h3 id="_2-4-ai-coding" tabindex="-1">2.4 AI Coding <a class="header-anchor" href="#_2-4-ai-coding" aria-label="Permalink to &quot;2.4 AI Coding&quot;">​</a></h3><p>让我比较震惊的是 AI 和 Coding 的结合。</p><p>前两年的时候，主要是以代码片段粒度为主， copolit 的辅助代码助手。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766626788324-image.png" alt=""></p><p>而去年的时候，演变成以文件粒度为主，能够改动单文件的工具。</p><p>而今年，变成了以模块/需求粒度，能自行交付任务的 Coding Agent。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766627858455-img_v3_02ta_83a850ae-3969-4493-9e7a-e74c73ae07bg.png" alt=""></p><p>或者有一些更直观的个人例子</p><ul><li>下半年算起，个人项目的代码应该有 90% 是他写的。</li><li>一个复杂需求中，用一个小时不到时间，完成本需要花一、两天的代码重构。</li></ul><p>如：此前让他集成一个 PDF 结合 RAG 的模块。</p><ul><li><p>拆解任务：拆解成一个一个小任务</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766628000218-image.png" alt=""></p></li><li><p>具体编码：几轮对话之后，基本就完成了编码。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766627394512-image.png" alt=""></p></li><li><p>最终效果：最终效果超出我原本的预想。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766628284685-image.png" alt=""></p></li></ul><p>再比如，国庆假期的时候，我也在编码。而到假期回头看的时候，也确实添加了不少功能。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766627797734-image.png" alt=""></p><p>过去这一年中，</p><p>AI Coding 的发展比我想象中的快很多，</p><p>22 年时候，让 ChatGPT 写一个简单的程序。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766628595908-img_v3_02ta_855fef10-de6e-4996-b048-d9ffa2c0f43g.jpg" alt=""></p><p>25 年的今天，我基本能让他自行完成一个需求。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766628697673-image.png" alt=""></p><p>实际上，我将 Coding Agent 看成是 Software Meta Builder</p><p>【构建软件的成本比以往降低了不少】</p><p>有种感觉“软件构建器”的概念。</p><p>有一种循环的感觉</p><p><strong>“构建工具 -&gt; 处理数据 -&gt; 构建工具 -&gt; 处理数据”。</strong></p><p><strong>同时，他也许不仅仅是工具的范围了。</strong></p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766628778737-image.png" alt=""></p><p>总得来说，在使用过程中，貌似 AI 已经是一个伙伴的角色。</p><h2 id="三、ai-对我的影响" tabindex="-1">三、AI 对我的影响 <a class="header-anchor" href="#三、ai-对我的影响" aria-label="Permalink to &quot;三、AI 对我的影响&quot;">​</a></h2><blockquote><p>我们塑造工具，随后工具塑造我们。 ——麦克卢汉</p></blockquote><p>在使用 AI 的过程中，</p><p>有些新的体会，</p><p>或者说，</p><p>AI 也在影响我们吧。</p><p>其实看科技发展历史，</p><p>会发现</p><ul><li>农作物的出现，让人们更注重计划。</li><li>时钟的出现，从而演化出了八小时工作制。</li><li>网络的出现，让我们时刻在线、信息过载、即使信息消费者，也是被消费者。</li></ul><p>……</p><p>而 AI 对我的影响，</p><p>我梳理成下方几点。</p><h3 id="_3-1-允执厥中" tabindex="-1">3.1 允执厥中 <a class="header-anchor" href="#_3-1-允执厥中" aria-label="Permalink to &quot;3.1 允执厥中&quot;">​</a></h3><blockquote><p>“不执两端，而取其中”</p></blockquote><p>“允执厥中”一词出自《尚书》</p><p>我的理解是**“在两个看似对立面之间，根据实际情况找到平衡**”。</p><p>这也是我今年在工作、生活的一大感悟。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766812046422-image.png" alt=""></p><p>但我没想到，今年 AI 也给我相关的启发。</p><p><strong>确定性与不确定性</strong></p><p>作为一名工程师，</p><p>在以往的开发中，</p><p>更多是做预设、确定性的场景，</p><p>给定了一定的输入，</p><p>也许会有大差不差的输出。</p><p>而 AI 工程更多是，</p><p>你给了一段输入，</p><p>可能会有各种，</p><p>甚至有相反的输出。</p><p>一开始会很不适应，</p><p>因为这种不确定性很难把控。</p><p>但也许，</p><p>确定性能保证下限，</p><p>而不确定性可能能突破上限。</p><p>需要根据具体场景做判断。</p><p><strong>场景与选择</strong></p><p>倘若你做 AI 工程应用,</p><p>大概会接触下方名词：</p><p>Function Calling, 通用 Agent, Skills, Workflow</p><p>并且你会发现，</p><p>没有哪种手段是完美的答案。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766664283627-image.png" alt=""></p><p>我对复杂度和通用性做了分类，</p><p>但实际的场景也比上方复杂的多，</p><p>并非所有任务都能落到象限中心，</p><p>更多的是，在象限的交界处。</p><p>需要判断好不同的任务场景，</p><p>从而选择不同的处理方式，</p><p>甚至可以将不同的方式做组合。</p><p><strong>理论和实践</strong></p><p>实际上，</p><p>这里我更希望称为<strong>抽象理论</strong>和<strong>具体实践。</strong></p><p>在做 AI 工程的时候，</p><p>我确实收集了很多关于 AI 工程的信息。</p><p>并且也把他拆成几个部分</p><p>知识库，MCP/工具，Memory，Agent Orchestrators 等。</p><p>貌似把这些模块做了集成就能得到不错的 Agent 效果，</p><p>但到具体实际落地的时候，</p><p>会有更重细节和场景，</p><p>如</p><ul><li>RAG 中：如何具体分 Chunk； PDF 中的图表如何做切分。</li><li>Agent Orchestrator： 自己实现的 ReACT 怎么就只能跑几轮。</li><li>Skills：为什么这个 skill 不执行。</li></ul><p>理论抽象固然重要，</p><p>而具体实践才能撑起理论，</p><p>并且修正此前的理论抽象。</p><p>这是一个往复的过程，</p><p>但能同时有宏观视角看事物，</p><p>又能微观视角落细节，</p><p>属实不易，</p><p>也在不断修炼中。</p><p>也许，大多情况下，</p><p>如果看清情况，</p><p>我们不需要过多极端的选择，</p><p>但我们可以判断选择是否极端。</p><h3 id="_3-2-规划与执行" tabindex="-1">3.2 规划与执行 <a class="header-anchor" href="#_3-2-规划与执行" aria-label="Permalink to &quot;3.2 规划与执行&quot;">​</a></h3><blockquote><p>钢铁、蒸汽是历史上出现的新材料，而 AI 也是一种材料，他带来无限的智力。</p></blockquote><p>你可能会觉得这句话有些眼熟，</p><p>没错，</p><p>这来源于 Notion CEO 前不久的一篇博客。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766667205355-image.png" alt=""></p><p>主要观点是：</p><p>AI 是新时代的原材料（无限的大脑），并从个人、组织、经济体举例可能的影响和变化。</p><p>我们需要认识到惯性，重新审视如何使用这种新型的材料。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766667132892-image.png" alt=""></p><p>也许你会感觉“无限地大脑”可能有点夸张，</p><p>但貌似已经有类型的场景了。</p><p>如在使用 Claude Code Web，</p><p>你可以指定好任务，</p><p>然后让 Coding Agent 做后续执行。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766667403080-image.png" alt=""></p><p>而到最后他确实能够交付任务，</p><p>如图中，Claude Code 已经完成了 10/20+ 任务。</p><p>而在我的感受中，</p><p>你需要做的是，</p><p>编排好任务，然后充足上下文，</p><p>就能够转动这个“无限的大脑”了。</p><p>但要做好这些并不容易，</p><p>这些要你能宏观编排，</p><p>又能有深入检查细节能力。</p><h3 id="_3-3-开环和闭环" tabindex="-1">3.3 开环和闭环 <a class="header-anchor" href="#_3-3-开环和闭环" aria-label="Permalink to &quot;3.3 开环和闭环&quot;">​</a></h3><p>这里的“闭环”并非互联网黑话，</p><p>而是控制论中的“开环/闭环”系统的概念。</p><p>“开环”系统：没有外部反馈输入。</p><p>“闭环”系统：会有外部反馈输入，从而调节自己的行为。</p><p>区别点在于是否有外部的反馈来更新自己行为。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766812293130-image.png" alt=""></p><p>而 AI 能够给我们带来反馈，</p><p>如</p><ul><li>问答本就是一种双向反馈的交互</li><li>AI 可以在具体的场景给你反馈建议。</li></ul><p>而这些反馈也许会改变你的动作。</p><p>但也要审视，</p><p>因为这些反馈并不一定准，</p><p>他只是外部给的一个信号，</p><p>很多时候需要做好判断。</p><p>比如今年 AI 给我的三个小建议是</p><ul><li>少想多做：理论够了，该动手了</li><li>走出去验证：自洽不等于正确，去验证</li><li>允许非理性：不是所有时间都要有意义</li></ul><p>实际上我觉得这几点也有道理，</p><p>但这也可能只是我的某一切面。</p><h3 id="_3-4-连点成线" tabindex="-1">3.4 连点成线 <a class="header-anchor" href="#_3-4-连点成线" aria-label="Permalink to &quot;3.4 连点成线&quot;">​</a></h3><blockquote><p>非结构化、非基于规则、语意的信息关联。</p></blockquote><p>我曾多次发表过：</p><p>“信息”应该是可关联的，</p><p>本质上是将非结构化信息通过非规则的手段，</p><p>进行语意的信息关联，</p><p>从而产生新的信息内容。</p><p>但这种关联，</p><p>并非仅通过“向量相似度计算”的关联，</p><p>而是检索之后还有生成的能力；</p><p>甚至语意完全不同的信息，</p><p>也可以做关联。</p><p>这样子你就可以做</p><ul><li>对比：对比两个方法的优劣之处，如方案 A 和方案 B的优点/缺点是啥</li><li>关系：了解统一分支下不同概念之间潜在的关系，如深度学习和机器学习的关系。</li><li>灵感：找到不同学科、信息中的交叉点，如哲学、工程、艺术是否存在某些观念。</li><li>细节点：能通过关联，找到相似的细节点。</li></ul><p>如下方关联 A2UI 和 GenUI 的例子</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766712182418-image.png" alt=""></p><p>我无法具体说清，</p><p>这种用法的好处。</p><p>但我觉得这种方法，</p><p>让我看到事物可能存在的关联点，</p><p>而在日常思考的过程中，</p><p>会无意识找到对应的关联点，</p><p>结合做具体的分析。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766711634866-image.png" alt=""></p><p><strong>那是种奇妙的感觉。</strong></p><h2 id="四、重新看待-ai" tabindex="-1">四、重新看待 AI <a class="header-anchor" href="#四、重新看待-ai" aria-label="Permalink to &quot;四、重新看待 AI&quot;">​</a></h2><h3 id="_4-1-客观理性看待" tabindex="-1">4.1 客观理性看待 <a class="header-anchor" href="#_4-1-客观理性看待" aria-label="Permalink to &quot;4.1 客观理性看待&quot;">​</a></h3><blockquote><p>AI 日益融进生活，更应该需要客观理性看待。</p></blockquote><p>一两年前的某一天，</p><p>我问了自己几个问题，</p><ul><li>我们今天所接触到的，到底是 AI、LLM、AIGC？</li><li>什么是 AGI， ASI，你又任何理解？</li><li>机器学习、深度学习、LLM 又是什么？</li><li>如何理解符号主义、连接主义、行为主义？</li></ul><p>当时，我发现我并不能回答好这个问题。</p><p>貌似今天接受到是 AI、LLM、AGI 的概念，</p><p>当然这有个好处是<strong>便于传播，减少沟通成本。</strong></p><p>但实际上传递的是模糊、压缩后的内容。</p><p>以个人见解，</p><p>今天我们接触比较多的，</p><p>可能叫 <strong>生成式 AI</strong> 更准确。</p><p>他是深度学习的子集</p><p>而深度学习是机器学习的子集，</p><p>而机器学习是 AI 的子集。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766714398402-generated-1766714398402-gwlmvjyve8b.png" alt=""></p><p>至于 AGI, ASI,</p><p>貌似有人提这些概念，</p><p>但并没有一个比较准确的描述。</p><p>我并不是说用这些词不好，</p><p>而是我觉得这些词会让人产生理解偏差。</p><p>而在今天的信息环境中，</p><p>关于 AI 的新闻充斥着整个环境，</p><p>但对于 AI 通识的内容信息却比较少。</p><p>但更重要的是，</p><p><strong>我们可能需要理解这些词背后的含义，</strong></p><p><strong>这样子也许能较为客观理性地看待 “AI”。</strong></p><h3 id="_4-2-ai-影响信息" tabindex="-1">4.2 AI 影响信息 <a class="header-anchor" href="#_4-2-ai-影响信息" aria-label="Permalink to &quot;4.2 AI 影响信息&quot;">​</a></h3><blockquote><p>AI 影响了重要元素，即信息，而信息是组成社会基础元素。</p></blockquote><p>本章节的观点，</p><p>实际上并非我原创，</p><p>更多是来源于赫拉利的两本书籍</p><ul><li>《人类简史》</li><li>《智人之上》</li></ul><p>如果读过这两本书，</p><p>相信你可能会和我有同样的观点。</p><p>《人类简史》中表明**“信息的重要性和基础性，实际上人类之所以能发展，也是靠信息来链接。”**</p><p>《智人之上》中表明**“ AI 实际上会影响信息层(如信息生产、分发、处理),从而获得更多主导权。”**</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766812411655-generated-1766812411655-j37nzu9sg5p.png" alt=""></p><p>而这种影响，大概率还是潜移默化的。</p><p>今年有两个例子</p><ul><li>网上 AI 生成内容数量已经超过了 人类生成内容数量。</li><li>我今年有几次对 AI 生成的假内容深信不疑，直到后面有人提醒。但也许还有很多我没留意到。</li></ul><p>甚至，</p><p>目前转变了观念，</p><p>社交媒体的信息，</p><p>默认判断为 AI 生成。</p><p><strong>这个趋势也许是不可逆的。</strong></p><h3 id="_4-3-ai-新媒介" tabindex="-1">4.3 AI 新媒介 <a class="header-anchor" href="#_4-3-ai-新媒介" aria-label="Permalink to &quot;4.3 AI 新媒介&quot;">​</a></h3><blockquote><p>AI 是新的媒介，不仅作为传播渠道，也修改/创造了传播的内容和形态。</p></blockquote><p><strong>“媒介即讯息”</strong>：媒介本身的特性和形式，比它所传播的具体内容，对社会和人类的影响更为深远和根本。</p><p>今天的 AI 影响了我们生产/消费传递内容的形态。</p><ul><li>生产：在生产侧，提供的内容/产品不再是预设的，而是根据场景动态变化的。</li><li>消费：在消费侧，接受者接受的内容也可以根据个人偏好做适配场景。</li></ul><p>这也意味着 AI 不仅仅是一个传输渠道，而且内容/产品的协作者。</p><p>至少在软件工程层面，</p><p>软件从原本较为确定的开发模式，</p><p>开始融入了 Agent 但不确定的开发模式。</p><p>借助这种能力，</p><p>软件中承载的内容/服务，</p><p><strong>也许能做到超出预设软件达不到的效果。</strong></p><p>也许这就像酿酒一样，</p><p>你需要塑造一个环境，</p><p>让微生物发挥他的能力，</p><p>也许你会得到一个普普通通的酒，</p><p>但也许也能得到未曾尝过的美妙滋味。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766812580999-generated-1766812580999-yeq488ttbth.png" alt=""></p><p>但更为重要的是，</p><p>你需要营造一个环境，</p><p>让 AI 这种新媒介生长、发挥作用。</p><p>当然这不限于软件工程。</p><p><strong>且也许我们需要用新视角来看待新的媒介。</strong></p><h3 id="_4-4-过程的压缩" tabindex="-1">4.4 过程的压缩 <a class="header-anchor" href="#_4-4-过程的压缩" aria-label="Permalink to &quot;4.4 过程的压缩&quot;">​</a></h3><blockquote><p>拥抱 AI，使用 AI， 但也具体分场景看，不要过分依赖，否则会造成“过程的压缩”。</p></blockquote><p>如果是 LLM 有个关键词是**“压缩”**，</p><p>那么这个词可能也适合放到这几年吧。</p><p>而对我而言，</p><p>更多的是**“过程的压缩/消失”。**</p><p>当通过提问能直接获取答案，</p><p>当通过描述需求就能生成代码，</p><p>当仅给点一个主题就生成长文。</p><p>貌似获得结果更快了，</p><p>但我却没有以前的乐趣。</p><p>也许是这过程被无限压缩了，</p><p>甚至“过程”直接消失了，</p><p>而也许我更希望在过程中找乐趣。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766812603382-generated-1766812603382-131fdcu24ezb.png" alt="图片-1"></p><p>也许这样子确实能提高效率，</p><p>但貌似在有些情况下，</p><p>我并不清楚里面的细节，</p><p>我不知道具体场景中有哪些难点，</p><p>我甚至无法给做出的结果做客观评价。</p><p>而当我回答不了上述的问题，</p><p>反过头来说，</p><p><strong>“这些结果真的是我做的么”</strong></p><p><strong>“Journey is the reward.”</strong></p><p>也许我们可以，</p><p>让部分过程不被压缩。</p><h2 id="写在最后" tabindex="-1">写在最后 <a class="header-anchor" href="#写在最后" aria-label="Permalink to &quot;写在最后&quot;">​</a></h2><p>写到这里，</p><p>这篇文章的结构、内容，</p><p>已经和我一开始想有所偏差。</p><p>有些点没能表达出来，</p><p>有些点表达得效果一般，</p><p>文章在细节上有点糙。</p><p>但也许这些是我目前所能表达的吧，</p><p>请读者多多体谅，也可直接给予反馈。</p><p><strong>外部的声音对我来说是稀有的财富。</strong></p><p><strong>作为一名信息爱好者，</strong></p><p><strong>我希望在这个</strong></p><p><strong>变化过快，信息过多，碎片化注意力</strong></p><p><strong>的时间段上</strong></p><p><strong>提供一点较好的视角，</strong></p><p><strong>分享一些个人的想法，</strong></p><p><strong>传播一些有趣的内容。</strong></p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766812237790-image.png" alt=""></p><p>希望这篇文章，</p><p>能在某个时刻，</p><p>对你有一点点帮助。</p>',418)])])}const d=o(g,[["render",s]]);export{m as __pageData,d as default};
